mapper.select:
SELECT DISTINCT t1.ID_ AS taskId, t1.NAME_ AS taskName, t2.NAME_ AS formName, t2.TENANT_ID_ AS systemSn, t2.BUSINESS_KEY_ AS businessKey, t2.PROC_INST_ID_ AS processInstanceId, t1.CREATE_TIME_ AS startTime, t1.SCOPE_TYPE_ scopeType FROM act_ru_task t1 INNER JOIN act_ru_execution t2 ON t1.PROC_INST_ID_ = t2.PROC_INST_ID_ LEFT JOIN act_ru_identitylink t3 ON t3.TASK_ID_ = t1.ID_
t1.ASSIGNEE_ = #{createId}
${sqlExtract}
AND (t1.PROC_INST_ID_ LIKE '%${keyword}%' OR t1.NAME_ LIKE '%${keyword}%')
AND t1.TENANT_ID_ = #{tenantId}
ORDER BY t1.CREATE_TIME_ DESC

SELECT DISTINCT e.PROC_INST_ID_ FROM act_ru_execution e INNER JOIN act_ru_variable v ON v.PROC_INST_ID_ = e.PROC_INST_ID_ WHERE e.IS_ACTIVE_ = 1 AND v.NAME_ = 'assignee' AND v.TEXT_ = #{userId} AND EXISTS ( SELECT 1 FROM act_ru_variable mv WHERE mv.PROC_INST_ID_ = e.PROC_INST_ID_ AND mv.NAME_ IN ('nrOfInstances', 'assigneeList') )
AND e.PROC_INST_ID_ LIKE '%${keyword}%'
AND e.TENANT_ID_ = #{tenantId}

SELECT DISTINCT e.PROC_INST_ID_ FROM act_ru_execution e INNER JOIN act_ru_variable v ON v.PROC_INST_ID_ = e.PROC_INST_ID_ WHERE e.IS_ACTIVE_ = 1 AND e.IS_SCOPE_ = 1 AND v.NAME_ = 'multiInstanceHostAssignee' AND v.TEXT_ = #{userId}
AND e.PROC_INST_ID_ LIKE '%${keyword}%'
AND e.TENANT_ID_ = #{tenantId}
